using System.Collections.Generic;
using UnityEngine;

public class AudioPlayer : MonoBehaviour
{
    public List<AudioClip> audioClips = new List<AudioClip>();
    public int selectedIndex = 0;

    private AudioSource audioSource;

    private void Awake()
    {
        audioSource = GetComponent<AudioSource>();
        if (audioSource == null)
        {
            audioSource = gameObject.AddComponent<AudioSource>();
        }
    }

    public void PlaySelected()
    {
        if (selectedIndex >= 0 && selectedIndex < audioClips.Count)
        {
            AudioManager.instance.Play(audioClips[selectedIndex], audioSource);
        }
    }

    public void Stop()
    {
        AudioManager.instance.Stop(audioSource);
    }

    public void Pause()
    {
        AudioManager.instance.Pause();
    }

    public void Resume()
    {
        AudioManager.instance.Resume();
    }
}

using System.Collections.Generic;
using UnityEngine;

public class AudioPlayer : MonoBehaviour
{
    public List<AudioClip> audioClips = new List<AudioClip>();
    public int selectedIndex;

    private AudioSource _audioSource;

    private void Awake()
    {
        _audioSource = GetComponent<AudioSource>();
        if (_audioSource == null)
        {
            _audioSource = gameObject.AddComponent<AudioSource>();
        }
    }

    public void PlaySelected()
    {
        if (selectedIndex >= 0 && selectedIndex < audioClips.Count)
        {
            AudioManager.instance.Play(audioClips[selectedIndex], _audioSource);
        }
    }

    public void Stop()
    {
        AudioManager.instance.Stop(_audioSource);
    }

    public void Pause()
    {
        AudioManager.instance.Pause();
    }

    public void Resume()
    {
        AudioManager.instance.Resume();
    }
}
